class Solution {
    public boolean possibleBipartition(int n, int[][] dislikes) {
        int[][] graph = new int[n][n];
        for (int[] dislike : dislikes) {
            graph[dislike[0]][dislike[1]] = 1;
            graph[dislike[1]][dislike[0]] = 1;
        }
        int[] count = new int[2];
        Arrays.fill(count, 0);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (graph[i][j] == 1) {
                    count[graph[i][j] - 1]++;
                }
            }
        }
        for (int i = 0; i < 2; i++) {
            if (count[i] > 0) {
                return false;
            }
        }
        return true;
    }
}
